from .common import *
LESSON_ID='lesson03'; TITLE='Bài 3 - Chỉ số ưu tiên ngành Priorityᵢ'; DESC='Xếp hạng 10 ngành theo tăng trưởng, lan tỏa, AI readiness và rủi ro.'
PARAMS=[{'key':'w_growth','label':'Trọng số tăng trưởng','default':0.15,'min':0,'max':0.5,'step':0.01},{'key':'w_productivity','label':'Trọng số năng suất','default':0.15,'min':0,'max':0.5,'step':0.01},{'key':'w_spillover','label':'Trọng số lan tỏa','default':0.20,'min':0,'max':0.5,'step':0.01},{'key':'w_export','label':'Trọng số xuất khẩu','default':0.15,'min':0,'max':0.5,'step':0.01},{'key':'w_employment','label':'Trọng số việc làm','default':0.10,'min':0,'max':0.5,'step':0.01},{'key':'w_ai','label':'Trọng số AI readiness','default':0.20,'min':0,'max':0.5,'step':0.01},{'key':'w_risk','label':'Phạt rủi ro tự động hóa','default':0.15,'min':0,'max':0.5,'step':0.01}]
def metadata(): return {'id':LESSON_ID,'title':TITLE,'description':DESC,'params':PARAMS,'module':'M2'}
def run(params=None):
    sectors=['Nông nghiệp','Chế biến','Xây dựng','Khai khoáng','Bán lẻ','Tài chính','Logistics','CNTT','Giáo dục','Y tế']; X=np.array([[3.27,103,0.35,40.5,13.2,15,18],[9.64,241,0.78,290.9,11.5,55,42],[7.45,169,0.42,2.5,4.8,20,25],[-1.2,1290,0.3,8.2,.3,30,55],[7.1,145,.55,5.5,7.8,48,38],[7.36,1072,.85,1.2,.55,72,52],[9.93,321,.72,3.1,1.95,42,35],[7.85,714,.92,178,.62,88,28],[6.42,206,.65,0,2.15,38,22],[6.85,437,.6,0,.75,45,18]],float)
    good=X[:,:6]; bad=X[:,6]; Gn=(good-good.min(0))/(np.ptp(good, axis=0)+1e-9); R=(bad-bad.min())/(np.ptp(bad)+1e-9)
    w=np.array([pget(params,k,d) for k,d in [('w_growth',.15),('w_productivity',.15),('w_spillover',.2),('w_export',.15),('w_employment',.1),('w_ai',.2)]],float); w=w/(w.sum()+1e-9); wr=pget(params,'w_risk',.15)
    score=Gn@w-wr*R; idx=np.argsort(-score); top=[sectors[i] for i in idx[:3]]
    return {'lesson':metadata(),'tabs':{'overview':{'metrics':[metric('Top ngành',1,'CNTT/Chế biến'),metric('Điểm cao nhất',score[idx[0]],''),metric('Phạt rủi ro',wr,'')],'chart':make_series([sectors[i] for i in idx],score[idx],'Priority')},'allocation':{'title':'Phân bổ ưu tiên theo ngành','chart':make_series([sectors[i] for i in idx[:5]],(score[idx[:5]]/score[idx[:5]].sum()*100),'Tỷ trọng ưu tiên'),'table':{sectors[i]:round(float(score[i]),3) for i in idx}},'scenarios':{'chart':make_compare(sectors,{'Mặc định':score,'AI-heavy':Gn@np.array([.08,.1,.15,.08,.09,.5])-wr*R,'Bao trùm':Gn@np.array([.1,.08,.25,.05,.32,.2])-wr*R}),'summary':'So sánh trọng số mặc định, AI-heavy và bao trùm.'},'risks':{'risk_score':float(R[idx[0]]),'level':risk_level(float(R[idx[0]])),'alerts':[f'Top-3 hiện tại: {", ".join(top)}','Cần cân bằng giữa AI readiness và rủi ro tự động hóa']}}}
